-- Pagina-tekst eerlijk kaderen: dit is de voorlichterspool uit recente edities.
UPDATE pages SET
  hero_lede = 'Professionals uit het werkveld vertellen open en eerlijk over hun vak. Hieronder een overzicht van voorlichters die in recente edities hun beroep presenteerden.',
  body_md = 'Elk jaar staan tientallen voorlichters klaar om leerlingen te vertellen over hun beroep — van architect tot kinderarts, van piloot tot loodgieter. Hieronder een overzicht uit recente edities. Het definitieve programma voor {{event_date_long}} maken we later bekend.

Wil je zelf je beroep presenteren? [Meld je aan als voorlichter](/aanmelden).'
WHERE slug = '/voorlichters';
